void mainImage( out vec4 fragColor, in vec2 fragCoord )
{
    float zoom = 10.0;
    float offset = 0.1;
    vec2 uv = fragCoord/iResolution.xy;
    uv.y *= iResolution.y/iResolution.x;
    uv*= zoom;
    vec2 i_uv = floor(uv);
    vec2 f_uv = fract(uv);
    vec3 col = vec3(0.0);
    float m_dist = 1.;
    for(int y = -1; y<=1;y++){
        for(int x = -1; x<=1;x++){
            vec2 neighbor = vec2(float(x), float(y));
            vec2 point = random2(i_uv + neighbor);
            point = vec2(0.5) + 0.5 *(sin(iTime+ 6.075 * point));
            vec2 diff = neighbor + point - f_uv ;
            diff +=  offset*random2(i_uv) * step(0.5, uv.x/10. );
            float dist = length(diff);
            m_dist = min(m_dist, dist);
        }
    }
    col += vec3(m_dist);
    col -= smoothstep(0., .1, abs(sin(27.0*m_dist)) - .8)*.5;
    col.b += 0.65;
    col.g += 0.35;
    fragColor = vec4(col,1.0);
}

