float map (in vec3 pos){
    vec3 centerBig = vec3(cos(iTime)*0.1 + sin(iTime*2.586)*0.1, max(0., cos(iTime)*0.1),0.);
    float d = length(pos - centerBig)-0.25;
    float d2 = pos.y - (-0.25);
    vec3 center = vec3(sin(iTime)*1. + cos(iTime*2.586)*1.,cos(iTime)*1.,-2.);
    float d3 = length(pos - center)-0.12;
    return min(d3,min(d2,d));
}

float mapSeeThrough (in vec3 pos){
    vec3 centerBig = vec3(cos(iTime)*0.1 + sin(iTime*2.586)*0.1, max(0., cos(iTime)*0.1),0.);
    float d = length(pos - centerBig)-0.25;
    float d2 = pos.y - (-0.25);
    float d3 = length(pos - vec3(sin(iTime)*1. + cos(iTime*2.586)*1.,cos(iTime)*1.,-2.))-0.12;
    float d4 = map(pos);
    return max(d3,d4);
}

vec3 calcNormal(in vec3 pos){
    vec2 e = vec2 (0.0001,0.0);
    return normalize(vec3(map(pos+e.xyy)-map(pos-e.xyy),
                         map(pos+e.yxy)-map(pos-e.yxy),
                         map(pos+e.yyx)-map(pos-e.yyx)));
}

float castRay(in vec3 ro, vec3 rd){
    float t = 0.;
    for(int i = 0; i<100; i++){
        vec3 pos = ro + t*rd;
        float h = map(pos);
        if(h<0.001) break;
        t += h;
        if(t>20.) break;
    }
    if(t>20.0) t=-1.;
    return t;
}

float castRayS(in vec3 ro, vec3 rd){
    float t = 0.;
    for(int i = 0; i<100; i++){
        vec3 pos = ro + t*rd;
        float h = mapSeeThrough(pos);
        if(h<0.001) break;
        t += h;
        if(t>20.) break;
    }
    if(t>20.0) t=-1.;
    return t;
}

void mainImage( out vec4 fragColor, in vec2 fragCoord ){
    vec2 p = (2. * fragCoord-iResolution.xy)/iResolution.y;
    vec3 ro = vec3(0.0,0.0,1.0);
    vec3 rd = normalize(vec3(p,-1.5));
    vec3 col = vec3(0.65,0.75,0.9) - 0.5*rd.y;
    float t = castRay(ro, rd);
    float t2 = castRayS(ro, rd);
    if(t>0.){
        vec3 pos = ro + t*rd;
        vec3 nor = calcNormal(pos);
        vec3 mate = vec3(0.18);
        vec3 sun_dir = vec3(0.8,0.4,0.2);
        float sky_dif = clamp(0.5 + 0.5*dot(nor, vec3(0.,1.,0.)), 0.,1.);
        float sun_dif = clamp(dot(nor, sun_dir), 0.0, 1.0);
        float sun_sha = step(castRay(pos+nor*0.001, sun_dir),0.0);
        float bou_dif = clamp(0.7 + 0.5* dot(nor, vec3(0.0,-1.0,0.0)), 0.0,0.1);
        col = mate * vec3(7.0,5.0,3.0)*sun_dif * sun_sha;
        col += mate *vec3(0.5,0.8,0.9)*sky_dif;
        col += mate * vec3(0.7,0.3,0.2)*bou_dif;
        if(t2>0.){
            vec3 pos2 = ro + t2*rd;
            vec3 nor2 = calcNormal(pos2);
            vec3 sun_dir2 = vec3(0.8,0.4,0.2);
            float sun_dif2 = clamp(dot(nor2, sun_dir2), 0.0, 1.0);
            col += vec3(0.1,0.2,5.)*sun_dif2;
        }
    }
    col = pow(col, vec3(0.4545));
    fragColor = vec4(col,1.0);
