#define MAX_STEPS 100
#define MAX_DIST 100.
#define SURF_DIST 0.01

float cd(vec3 p, vec3 a, vec3 b, float r){
    vec3 ab = b-a;
    vec3 ap = p-a;
    float t = dot(ab, ap)/dot(ab, ab);
    t = clamp(t, 0.,1.);
    vec3 c = a + t*ab;
    return length(p-c)-r;
}

float GetDist(vec3 p){
    float planeDist = p.y;
    vec3 topP = vec3(2., 3., 5.);
    topP.x += sin(iTime);
    topP.y += cos(iTime);
    float capDist = cd(p, vec3(-2., 1., 3.), topP, 1.);
    return min(capDist, planeDist);
}

float RayMarch(vec3 ro, vec3 rd){
    float dO = 0.;
    for(int i = 0; i<MAX_STEPS; i++){
        vec3 p = ro + rd*dO;
        float dS = GetDist(p);
        dO += dS;
        if(dO>MAX_DIST || dS<SURF_DIST) break;
    }
    return dO;
}

vec3 GetNormal(vec3 p){
    float d = GetDist(p);
    vec2 e = vec2(.01, 0.);
    vec3 n = d - vec3(GetDist(p-e.xyy), GetDist(p-e.yxy), GetDist(p-e.yyx));
    return normalize(n);
}

float GetLight(vec3 p, vec3 lightPos){
    vec3 l = normalize(lightPos - p);
    vec3 n = GetNormal(p);
    float dif = clamp(dot(n, l),0.,1.);
    float d = RayMarch(p + n*SURF_DIST * 2.,l);
    if(d<length(lightPos - p)) dif *= .2;
    return dif;
}

void mainImage( out vec4 fragColor, in vec2 fragCoord ){
    vec2 uv = fragCoord/iResolution.xy;
    uv = (uv- 0.5) *2.;
    uv.x *= iResolution.x/iResolution.y;
    uv.y += sin(iTime*1.5+sin(uv.x*12.0))*0.05;
    vec3 col = vec3(0.1);
    vec3 ro = vec3(0.,1.,0.);
    vec3 rd = normalize(vec3(uv.x, uv.y, 1. - uv.x*sin(iTime)));
    float d = RayMarch(ro, rd);
    vec3 p = ro + rd * d;
    float dif = GetLight(p, vec3(0., 7., 3.));
    dif += GetLight(p, vec3(3., 2., 1.));
    d /= 6.;
    col += vec3(0.2 + uv.x*0.2,0.5 + uv.x *-0.6,0.7)*dif;
    fragColor = vec4(col,1.0);
}

