vec3 czm_saturation(vec3 rgb, float adjustment){
    const vec3 W = vec3(0.2125, 0.7145, 0.0721);
    vec3 intensity = vec3(dot(rgb, W));
    return mix(intensity, rgb, adjustment);
}

vec3 hueShift(vec3 color, float hue){
    vec3 k = vec3(0.57735);
    float cosAngle = cos(hue);
    return vec3(color * cosAngle + cross(k, color) * sin(hue) + k * dot(k, color) * (1.0-cosAngle));
}

vec3 sceneColor(vec2 uv){
    float a = 0.5 + 0.5 * sin(uv.x * 8.0 + iTime * 0.7);
    float b = 0.5 + 0.5 * cos(uv.y * 6.0 - iTime * 0.5);
    float c = 0.5 + 0.5 * sin((uv.x + uv.y) * 5.0 + iTime);
    return vec3(a, b, c);
}

void mainImage( out vec4 fragColor, in vec2 fragCoord ){
    vec2 uv = fragCoord/iResolution.xy;
    uv.x += floor(iTime * 0.0025 + 3.0 * uv.x) * 0.05;
    uv.x = mod(uv.x, 1.);
    float drip = fract(sin(uv.x * 91.7 + uv.y * 47.3) * 4321.0);
    vec3 color = sceneColor(uv);
    color = hueShift(color, iTime * 0.5 + 10. * uv.y);
    color.g *= 1.1;
    float lumin = dot(color,vec3(1.0))/3.;
    color *= lumin;
    color += color;
    color = czm_saturation(color, drip * 15. * lumin);
    fragColor = vec4(color, 1.);
}

